import { useEffect, useRef } from 'react';

interface MouseState {
  x: number;       // Pixel X coordinate relative to container top-left
  y: number;       // Pixel Y coordinate relative to container top-left
  active: boolean; // True if cursor is hovering over the container
}

/**
 * High-performance hook to track mouse coordinates inside a container element ref.
 * Persists data inside a mutable React ref instead of state to prevent triggering
 * component re-renders during mouse movements.
 */
export function useMouseInfluence(containerRef: React.RefObject<HTMLElement | null>) {
  const mouseStateRef = useRef<MouseState>({
    x: 0,
    y: 0,
    active: false,
  });

  useEffect(() => {
    const element = containerRef.current;
    if (!element) return;

    if (typeof window === "undefined") return;

    // Skip tracking if prefers-reduced-motion is enabled
    const mediaQuery = window.matchMedia("(prefers-reduced-motion: reduce)");
    if (mediaQuery.matches) {
      mouseStateRef.current.active = false;
      return;
    }

    const handleMouseMove = (event: MouseEvent) => {
      const rect = element.getBoundingClientRect();

      // Calculate coordinates relative to the top-left boundary of the grid container
      mouseStateRef.current.x = event.clientX - rect.left;
      mouseStateRef.current.y = event.clientY - rect.top;
      mouseStateRef.current.active = true;
    };

    const handleMouseEnter = () => {
      mouseStateRef.current.active = true;
    };

    const handleMouseLeave = () => {
      mouseStateRef.current.active = false;
    };

    element.addEventListener("mousemove", handleMouseMove, { passive: true });
    element.addEventListener("mouseenter", handleMouseEnter, { passive: true });
    element.addEventListener("mouseleave", handleMouseLeave, { passive: true });

    return () => {
      element.removeEventListener("mousemove", handleMouseMove);
      element.removeEventListener("mouseenter", handleMouseEnter);
      element.removeEventListener("mouseleave", handleMouseLeave);
    };
  }, [containerRef]);

  return mouseStateRef;
}

export default useMouseInfluence;

"use client";

import { useEffect, useRef } from 'react';

/**
 * Executes a high-performance requestAnimationFrame loop.
 * Supports capping frame rate to a target FPS (e.g. 30 FPS) and computes delta time.
 */
export function useRAF(
  callback: (timeSeconds: number, deltaTimeSeconds: number) => void,
  active = true,
  fps = 60
) {
  const savedCallback = useRef(callback);
  const requestRef = useRef<number | null>(null);
  const previousTimeRef = useRef<number | null>(null);
  const accumulatedTimeRef = useRef<number>(0);

  useEffect(() => {
    savedCallback.current = callback;
  }, [callback]);

  useEffect(() => {
    if (!active) {
      if (requestRef.current !== null) {
        cancelAnimationFrame(requestRef.current);
        requestRef.current = null;
      }
      previousTimeRef.current = null;
      return;
    }

    const frameIntervalMs = 1000 / fps;

    const tick = (timestampMs: number) => {
      if (previousTimeRef.current === null) {
        previousTimeRef.current = timestampMs;
        requestRef.current = requestAnimationFrame(tick);
        return;
      }

      const elapsedMs = timestampMs - previousTimeRef.current;

      if (elapsedMs >= frameIntervalMs) {
        // Adjust for clock drift
        previousTimeRef.current = timestampMs - (elapsedMs % frameIntervalMs);

        const deltaTimeSeconds = elapsedMs / 1000;
        accumulatedTimeRef.current += deltaTimeSeconds;

        savedCallback.current(accumulatedTimeRef.current, deltaTimeSeconds);
      }

      requestRef.current = requestAnimationFrame(tick);
    };

    requestRef.current = requestAnimationFrame(tick);

    return () => {
      if (requestRef.current !== null) {
        cancelAnimationFrame(requestRef.current);
      }
    };
  }, [active, fps]);
}
export default useRAF;

/**
 * Calculates the standard Euclidean distance between two points (x1, y1) and (x2, y2).
 */
export function getEuclideanDistance(x1: number, y1: number, x2: number, y2: number): number {
  const dx = x2 - x1;
  const dy = y2 - y1;
  return Math.sqrt(dx * dx + dy * dy);
}

/**
 * Calculates the Chebyshev distance (maximum coordinate difference) between two points.
 * Useful for grid-based expansions.
 */
export function getChebyshevDistance(x1: number, y1: number, x2: number, y2: number): number {
  return Math.max(Math.abs(x2 - x1), Math.abs(y2 - y1));
}

/**
 * Calculates the Manhattan distance (L1 norm) between two points.
 */
export function getManhattanDistance(x1: number, y1: number, x2: number, y2: number): number {
  return Math.abs(x2 - x1) + Math.abs(y2 - y1);
}

// Self-contained 2D Perlin noise implementation for organic led shifting textures
class PerlinNoise {
  private p: number[] = new Array(512);

  constructor(seed = 42) {
    const permutation = Array.from({ length: 256 }, (_, i) => i);

    // Seeded random number generator
    const random = (s: number) => {
      const x = Math.sin(s) * 10000;
      return x - Math.floor(x);
    };

    let currentSeed = seed;
    // Shuffle permutation array
    for (let i = 255; i > 0; i--) {
      const r = Math.floor(random(currentSeed++) * (i + 1));
      const temp = permutation[i];
      permutation[i] = permutation[r];
      permutation[r] = temp;
    }

    // Duplicate permutation array
    for (let i = 0; i < 256; i++) {
      this.p[i] = permutation[i];
      this.p[256 + i] = permutation[i];
    }
  }

  private fade(t: number) {
    return t * t * t * (t * (t * 6 - 15) + 10);
  }

  private lerp(t: number, a: number, b: number) {
    return a + t * (b - a);
  }

  private grad(hash: number, x: number, y: number) {
    // Convert low 3 bits of hash code into 8 gradient directions
    const h = hash & 7;
    const u = h < 4 ? x : y;
    const v = h < 4 ? y : x;
    return ((h & 1) ? -u : u) + ((h & 2) ? -2.0 * v : 2.0 * v);
  }

  public noise(x: number, y: number): number {
    const X = Math.floor(x) & 255;
    const Y = Math.floor(y) & 255;

    x -= Math.floor(x);
    y -= Math.floor(y);

    const u = this.fade(x);
    const v = this.fade(y);

    const A = this.p[X] + Y;
    const B = this.p[X + 1] + Y;

    const val = this.lerp(v,
      this.lerp(u, this.grad(this.p[A], x, y), this.grad(this.p[B], x - 1, y)),
      this.lerp(u, this.grad(this.p[A + 1], x, y - 1), this.grad(this.p[B + 1], x - 1, y - 1))
    );

    // Normalize result between -1.0 and 1.0
    return val * 0.5;
  }
}

let defaultNoiseInstance: PerlinNoise | null = null;
const noiseCache = new Map<number, PerlinNoise>();

/**
 * Returns a 2D Perlin noise value between -1.0 and 1.0.
 */
export function noise2D(x: number, y: number, seed = 42): number {
  if (seed === 42) {
    if (!defaultNoiseInstance) {
      defaultNoiseInstance = new PerlinNoise(42);
    }
    return defaultNoiseInstance.noise(x, y);
  }

  let noiseObj = noiseCache.get(seed);
  if (!noiseObj) {
    noiseObj = new PerlinNoise(seed);
    noiseCache.set(seed, noiseObj);
  }

  return noiseObj.noise(x, y);
}
